(430, NULL, 'Microsoft Excel, Word and PowerPoint', 'Microsoft Excel, Word dan PowerPoint', 'Microsoft Excel, Word dan PowerPoint', 'Materi ini dibuat berdasarkan case yang sering dihadapi di dunia pekerjaan yang sudah saya geluti bertahun-tahun. Sehingga potensinya besar banget buat kamu semua untuk faham secara mendalam.', NULL, NULL, NULL, '4,59', 'Dasar', 'Myskill', '2026-07-05 03:21:14'),
(431, NULL, 'UI-UX Research and Design', 'Figma, UX Design, UX Research, serta UI Design', 'Figma, UX Design, UX Research, serta UI Design', 'Materi ini dibuat berdasarkan proses dari awal saya berkarir di dunia UI/UX selama 5 tahun. Segala detail dan proses kerja, saya coba tuangkan di tiap materi yang disampaikan', NULL, NULL, NULL, '4,6', 'Dasar', 'Myskill', '2026-07-05 03:21:14'),
(432, NULL, 'Website & Apps Development', 'Front End, Back End', 'Front End, Back End', 'Perancangan materi ini berlandaskan pengalaman yang telah ditempuh selama 10 tahun dalam bidang Web Development. Penyusunannya pun dengan langkah-perlangkah yang dibutuhkan secara menyeluruh', NULL, NULL, NULL, '4,5', 'Dasar', 'Myskill', '2026-07-05 03:21:14'),
